def cache_result(expiry=CACHE_EXPIRY, key_prefix=''):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            cache_key_parts = [key_prefix or func.__name__]
            
            for arg in args:
                if isinstance(arg, (str, int, float, bool)):
                    cache_key_parts.append(str(arg)[:50])
            
            for k, v in sorted(kwargs.items()):
                if isinstance(v, (str, int, float, bool)):
                    cache_key_parts.append(f"{k}:{str(v)[:50]}")
            
            cache_key_raw = ':'.join(cache_key_parts)
            cache_key_hash = hashlib.sha256(cache_key_raw.encode()).hexdigest()[:32]
            
            try:
                full_cache_key = get_cache_key(f"{key_prefix or func.__name__}:{cache_key_hash}")
                
                cached = redis_client.get(full_cache_key)
                if cached:
                    logger.info(f"Cache hit for {func.__name__}")
                    return json.loads(cached)
                
                result = func(*args, **kwargs)
                
                redis_client.setex(
                    full_cache_key,
                    expiry,
                    json.dumps(result)
                )
                logger.info(f"Cache miss for {func.__name__}, result cached")
                return result
                
            except (redis.RedisError, json.JSONDecodeError) as e:
                logger.error(f"Cache error, executing function directly: {str(e)}")
                return func(*args, **kwargs)
        
        return wrapper
    return decorator

def invalidate_cache(key_pattern):
    try:
        sanitized_pattern = sanitize_cache_key(key_pattern)
        full_pattern = f"{CACHE_PREFIX}{sanitized_pattern}*"
        
        cursor = 0
        while True:
            cursor, keys = redis_client.scan(cursor, match=full_pattern, count=100)
            if keys:
                redis_client.delete(*keys)
            if cursor == 0:
                break
        logger.info(f"Cache invalidated for pattern: {key_pattern}")
    except redis.RedisError as e:
        logger.error(f"Error invalidating cache: {str(e)}")

